3574 // Floating-point equality is not an equivalence when comparing +0.0 with
3575 // -0.0, when comparing NaN with another value, or when flushing
3576 // denormals-to-zero.
3577 bool CmpInst::isEquivalence(bool Invert) const {
3578   switch (Invert ? getInversePredicate() : getPredicate()) {
3579   case CmpInst::Predicate::ICMP_EQ:
3580     return true;
3581   case CmpInst::Predicate::FCMP_UEQ:
3582     if (!hasNoNaNs())
3583       return false;
3584     [[fallthrough]];
3585   case CmpInst::Predicate::FCMP_OEQ:
3586     return hasNonZeroFPOperands(this);
3587   default:
3588     return false;
3589   }
3590 }
